import React, { useState } from 'react';
import './BookCard.css';

function Stars({ rating }) {
  const full = Math.floor(rating);
  const half = rating - full >= 0.5;
  return (
    <div className="bc-stars">
      {[1,2,3,4,5].map(s => (
        <span key={s} className={
          s <= full ? 'bc-star bc-star--full' :
          s === full + 1 && half ? 'bc-star bc-star--half' :
          'bc-star'
        }>★</span>
      ))}
    </div>
  );
}

export default function BookCard({ title, author, image, rating, votes, rank, delay = 0 }) {
  const [loaded, setLoaded] = useState(false);

  return (
    <div className="bc" style={{ animationDelay: `${delay}ms` }}>

      {/* Cover image */}
      <div className="bc__cover">
        {!loaded && <div className="bc__cover-skeleton skeleton" />}
        <img
          src={image}
          alt={title}
          onLoad={() => setLoaded(true)}
          style={{ opacity: loaded ? 1 : 0 }}
        />
        {rank && <span className="bc__rank">#{rank}</span>}
      </div>

      {/* Info */}
      <div className="bc__info">
        <p className="bc__author">{author}</p>
        <h3 className="bc__title">{title}</h3>
        <div className="bc__bottom">
          <Stars rating={rating ?? 0} />
          <span className="bc__votes">{votes?.toLocaleString()} votes</span>
        </div>
      </div>

    </div>
  );
}
